import{_ as l,H as i,f as t,i as e}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"设计模式系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../designPatternLearning/00-写作计划.md","filePath":"../designPatternLearning/00-写作计划.md","lastUpdated":1779559313000}'),s={name:"../designPatternLearning/00-写作计划.md"};function n(p,a,r,o,d,h){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="设计模式系列写作计划" tabindex="-1">设计模式系列写作计划 <a class="header-anchor" href="#设计模式系列写作计划" aria-label="Permalink to &quot;设计模式系列写作计划&quot;">​</a></h1><blockquote><p>这个系列面向已经能写业务代码,但开始频繁遇到&quot;代码越改越乱&quot;的工程师。 它不把设计模式写成 23 个名词背诵表,而是回答一个更实际的问题:当需求变化、团队协作、框架约束、测试维护一起压上来时,代码结构应该怎么长。 MVC / MVP / MVVM 也会讲,但它们属于应用架构模式,不是 GoF 设计模式。这个边界必须先讲清楚。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>五层结构,从&quot;为什么需要模式&quot;到&quot;真实项目怎么落地&quot;:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模式心智与原则</span></span>
<span class="line"><span>   -&gt; GoF 设计模式(创建型 / 结构型 / 行为型)</span></span>
<span class="line"><span>   -&gt; 应用架构模式(MVC / MVP / MVVM / 分层 / 六边形 / DDD)</span></span>
<span class="line"><span>   -&gt; 前端与客户端模式(组件 / 状态管理 / 单向数据流 / 微前端)</span></span>
<span class="line"><span>   -&gt; 工程判断(重构 / 反模式 / 选型 / 模式滥用)</span></span></code></pre></div><p>本系列的重点不是&quot;这个模式的 UML 图长什么样&quot;,而是:</p><ul><li>它解决哪一种变化</li><li>它把复杂度从哪里搬到哪里</li><li>它适合什么语言和框架</li><li>它什么时候会变成过度设计</li><li>它在 Spring / React / Vue / Flutter / Go / Rust 等真实生态里对应什么写法</li></ul><p>每篇尽量用同一个套路:</p><ol><li>先给一个没有模式时会坏掉的代码结构</li><li>再抽出变化点和稳定点</li><li>然后引入模式</li><li>最后讲代价、误用和替代方案</li></ol><hr><h2 id="篇目规划" tabindex="-1">篇目规划 <a class="header-anchor" href="#篇目规划" aria-label="Permalink to &quot;篇目规划&quot;">​</a></h2><h3 id="第一层-心智与基础-01-05" tabindex="-1">第一层:心智与基础(01-05) <a class="header-anchor" href="#第一层-心智与基础-01-05" aria-label="Permalink to &quot;第一层:心智与基础(01-05)&quot;">​</a></h3><ul><li>[x] 01 设计模式总览:模式不是背诵题,是变化管理工具</li><li>[x] 02 UML 与代码结构图速通:类图、依赖、组合、聚合、时序图</li><li>[x] 03 SOLID 原则:哪些有用,哪些容易被误解</li><li>[x] 04 组合优于继承:复用、扩展点与抽象层的真实代价</li><li>[x] 05 依赖倒置与依赖注入:从 new 到 IoC 容器</li></ul><h3 id="第二层-创建型模式-06-10" tabindex="-1">第二层:创建型模式(06-10) <a class="header-anchor" href="#第二层-创建型模式-06-10" aria-label="Permalink to &quot;第二层:创建型模式(06-10)&quot;">​</a></h3><ul><li>[x] 06 单例模式:全局唯一、生命周期与测试噩梦</li><li>[x] 07 工厂方法与抽象工厂:把创建逻辑从业务里拔出来</li><li>[x] 08 建造者模式:复杂对象、可读参数与不可变配置</li><li>[x] 09 原型模式:复制对象、快照与模板化创建</li><li>[x] 10 对象池与资源池:连接池、线程池与复用边界</li></ul><h3 id="第三层-结构型模式-11-17" tabindex="-1">第三层:结构型模式(11-17) <a class="header-anchor" href="#第三层-结构型模式-11-17" aria-label="Permalink to &quot;第三层:结构型模式(11-17)&quot;">​</a></h3><ul><li>[x] 11 适配器模式:旧接口、新接口与第三方 SDK 包装</li><li>[x] 12 装饰器模式:不改原类也能叠能力</li><li>[x] 13 代理模式:远程代理、缓存代理、权限代理与 AOP</li><li>[x] 14 外观模式:给复杂子系统一个稳定入口</li><li>[x] 15 组合模式:树形结构、菜单、文件系统与 UI 组件</li><li>[x] 16 桥接模式:两个维度独立变化时怎么拆</li><li>[x] 17 享元模式:大量小对象的内存优化</li></ul><h3 id="第四层-行为型模式-18-27" tabindex="-1">第四层:行为型模式(18-27) <a class="header-anchor" href="#第四层-行为型模式-18-27" aria-label="Permalink to &quot;第四层:行为型模式(18-27)&quot;">​</a></h3><ul><li>[x] 18 策略模式:消灭 if-else,但别制造类爆炸</li><li>[x] 19 模板方法模式:框架钩子、生命周期与反向控制</li><li>[x] 20 观察者模式:事件、订阅、响应式与内存泄漏</li><li>[x] 21 发布订阅模式:EventBus、消息队列与观察者的边界</li><li>[x] 22 命令模式:撤销、重做、队列化与操作日志</li><li>[x] 23 状态模式:把状态机从 if-else 里救出来</li><li>[x] 24 责任链模式:中间件、过滤器、审批流与错误传播</li><li>[x] 25 迭代器模式:遍历协议、惰性序列与流式处理</li><li>[x] 26 访问者模式:AST、编译器 Pass 与表达式问题</li><li>[x] 27 解释器模式:DSL、小语言与规则引擎的边界</li></ul><h3 id="第五层-应用架构模式-28-37" tabindex="-1">第五层:应用架构模式(28-37) <a class="header-anchor" href="#第五层-应用架构模式-28-37" aria-label="Permalink to &quot;第五层:应用架构模式(28-37)&quot;">​</a></h3><ul><li>[x] 28 MVC:Model、View、Controller 到底分什么</li><li>[x] 29 MVP:Presenter 为什么适合测试,又为什么少见了</li><li>[x] 30 MVVM:ViewModel、数据绑定与响应式 UI</li><li>[x] 31 分层架构:Controller / Service / Repository 的边界</li><li>[x] 32 六边形架构:端口、适配器与业务核心保护</li><li>[x] 33 Clean Architecture:用例层、实体层与依赖规则</li><li>[x] 34 DDD 战术模式:Entity、Value Object、Aggregate、Repository</li><li>[x] 35 CQRS:读写模型分离,不是所有系统都需要</li><li>[x] 36 事件驱动架构:领域事件、集成事件与最终一致性</li><li>[x] 37 微服务模式:服务拆分、Saga、API Gateway 与反腐层</li></ul><h3 id="第六层-前端与客户端模式-38-45" tabindex="-1">第六层:前端与客户端模式(38-45) <a class="header-anchor" href="#第六层-前端与客户端模式-38-45" aria-label="Permalink to &quot;第六层:前端与客户端模式(38-45)&quot;">​</a></h3><ul><li>[x] 38 组件模式:Props、Slots、Composition 与复用边界</li><li>[x] 39 单向数据流:Flux / Redux / Elm 架构的核心约束</li><li>[x] 40 响应式模式:Observable、Signals、Computed 与副作用</li><li>[x] 41 状态管理模式:本地状态、服务端状态、全局状态怎么分</li><li>[x] 42 容器组件与展示组件:什么时候有用,什么时候过时</li><li>[x] 43 Hooks / Composable 模式:逻辑复用的新默认</li><li>[x] 44 路由与页面模式:嵌套路由、布局、加载器与守卫</li><li>[x] 45 微前端模式:模块联邦、沙箱、路由隔离与组织边界</li></ul><h3 id="第七层-工程判断与反模式-46-50" tabindex="-1">第七层:工程判断与反模式(46-50) <a class="header-anchor" href="#第七层-工程判断与反模式-46-50" aria-label="Permalink to &quot;第七层:工程判断与反模式(46-50)&quot;">​</a></h3><ul><li>[x] 46 重构到模式:从坏味道开始,不要从模式开始</li><li>[x] 47 常见反模式:上帝对象、贫血模型、过度抽象、回调地狱</li><li>[x] 48 模式与语言特性:Java、Go、Rust、TypeScript 写法为什么不同</li><li>[x] 49 模式选型清单:需求变化点、团队能力、测试成本与性能约束</li><li>[x] 50 设计模式面试与真实代码评审:怎么讲清取舍,不背模板</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>React / Vue / Angular / Solid 框架使用</td><td>webLearning ✅</td><td>不重复框架 API,只讲背后的架构模式</td></tr><tr><td>Flutter 状态管理</td><td>flutterLearning ✅</td><td>不重复具体库教程,只讲 MVVM / 响应式 / 组件模式</td></tr><tr><td>系统设计与高并发架构</td><td>systemDesign ✅</td><td>不讲百万 QPS 架构,只讲代码结构和模块边界</td></tr><tr><td>分布式事务 / 共识 / Saga 理论</td><td>distributedLearning ✅</td><td>Saga 只作为微服务模式的一部分出现</td></tr><tr><td>Go / Rust 语法与工程</td><td>goLearning / rustLearning ✅</td><td>只讲同一个模式在不同语言里的不同形态</td></tr><tr><td>解释器 AST / Visitor</td><td>interpreterLearning ✅</td><td>Visitor 只讲模式心智,深入 AST 仍看解释器系列</td></tr><tr><td>Agent / Skill 设计模式</td><td>claudeLearning ✅</td><td>不展开 AI Agent 专题,只在模式思想上做类比</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇优先按四段式写:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 问题</span></span>
<span class="line"><span>   - 没有这个模式时,代码怎么坏</span></span>
<span class="line"><span>   - 变化点是什么,稳定点是什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 模式</span></span>
<span class="line"><span>   - 角色分工</span></span>
<span class="line"><span>   - 简化 UML / 结构图</span></span>
<span class="line"><span>   - 最小代码示例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 落地</span></span>
<span class="line"><span>   - 在主流框架或语言里的真实形态</span></span>
<span class="line"><span>   - 测试、扩展、性能、并发上的影响</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 代价</span></span>
<span class="line"><span>   - 什么时候不该用</span></span>
<span class="line"><span>   - 常见误用</span></span>
<span class="line"><span>   - 替代方案</span></span></code></pre></div><p>代码示例要短,优先 TypeScript / Java / Go 三种表达力强、读者容易迁移的语言。能用伪代码讲清楚时,不要贴一整套框架项目。</p><hr><h2 id="最小阅读路径" tabindex="-1">最小阅读路径 <a class="header-anchor" href="#最小阅读路径" aria-label="Permalink to &quot;最小阅读路径&quot;">​</a></h2><p>如果只想理解 MVC / MVVM 以及日常业务代码怎么分层:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 03 -&gt; 04 -&gt; 05 -&gt; 18 -&gt; 20 -&gt; 28 -&gt; 29 -&gt; 30 -&gt; 31 -&gt; 32 -&gt; 38 -&gt; 39 -&gt; 41</span></span></code></pre></div><p>如果想系统补 GoF 设计模式:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 02 -&gt; 03 -&gt; 06-27 -&gt; 46 -&gt; 48 -&gt; 49</span></span></code></pre></div><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列不写这些东西:</p><ol><li>把 23 个 GoF 模式逐个翻译定义,没有真实变化场景</li><li>为了用模式而用模式,把简单代码拆成十几个类</li><li>只贴 UML,不解释为什么这样切边界</li><li>把 MVC / MVVM 和单例 / 工厂混在一个分类里</li><li>只讲 Java 经典写法,忽略现代语言的函数、闭包、trait、泛型、ADT</li><li>把设计模式写成面试八股,不讲代码评审和维护成本</li></ol><hr><h2 id="一个硬指标" tabindex="-1">一个硬指标 <a class="header-anchor" href="#一个硬指标" aria-label="Permalink to &quot;一个硬指标&quot;">​</a></h2><p>看完这个系列后,你应该能在代码评审里讲清楚:</p><ul><li>这个抽象是在保护哪个变化点</li><li>这个模式让测试变容易还是变困难</li><li>现在引入它是不是过早</li><li>用语言特性或框架机制能不能更简单地解决</li><li>MVC / MVP / MVVM / 分层 / 六边形之间到底差在哪</li></ul><p>能做到这些,设计模式就从&quot;背过&quot;变成了&quot;会用&quot;。</p>`,49)])])}const x=l(s,[["render",n]]);export{u as __pageData,x as default};
